var e=[{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`언니! 어딜 가는 거야?`,JPN:`お姉ちゃん！　どこに行くの！？`,ENG:`Yuri! Where are you going?`,TWN:`姊姊！妳要去哪裡？`},stage:{bg:`black`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`......이유미, 넌 거기 숨어 있어.`,JPN:`……ユミ、そこに隠れていて。`,ENG:`You just hide in there, Yumi.`,TWN:`……李悠美，好好躲在那裡。`},stage:{bg:`black`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`언니가 나오라고 할 때까지 절대로 나오면 안 돼.`,JPN:`お姉ちゃんが出て来ていいって言うまで、絶対に出ちゃダメ。`,ENG:`Don't come out until I tell you, no matter what.`,TWN:`在我回來之前，千萬別出來。`},stage:{bg:`black`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:null,text:{KOREA:`엄마...... 아빠!`,JPN:`お母さん……お父さん！`,ENG:`Mom... Dad!`,TWN:`媽媽……爸爸！`},stage:{bg:`black`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`안 돼!!!`,JPN:`ダメ！！`,ENG:`No!`,TWN:`不！！！`},stage:{bg:`black`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:null,text:{KOREA:`어, 어째서...... 불이......`,JPN:`ど、どうして……火が……`,ENG:`W-why is the house on fire?`,TWN:`怎、怎麼會……火……`},stage:{bg:`black`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:null,text:{KOREA:`왜 그렇게 떨고 있는 거야, 꼬맹아?`,JPN:`なぜそんなに震えているんだい、お嬢ちゃん。`,ENG:`Why are you trembling, kid?`,TWN:`妳為什麼在顫抖，孩子？`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:null,text:{KOREA:`내가 무섭니?`,JPN:`俺が怖いか？`,ENG:`Do I scare you?`,TWN:`害怕我嗎？`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`아니야.`,JPN:`ちがう。`,ENG:`No.`,TWN:`不。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`난 두렵지 않아.`,JPN:`私は怖くない。`,ENG:`I'm not scared.`,TWN:`我不怕。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`내가...... 내가 가족을 지켜야만 해.`,JPN:`私が……私が家族を守らなければならない。`,ENG:`I must... I must protect my family.`,TWN:`我……我一定要保護家人。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`내가......`,JPN:`私が……`,ENG:`I...`,TWN:`我……`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:null,text:{KOREA:`내가...... 지키지 못 했어.`,JPN:`私は……守れなかった。`,ENG:`I... couldn't protect them.`,TWN:`我……沒能保護好。`},stage:{bg:`black`,slots:{L:null,C:null,R:null}}},{id:`L28_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`dormitory_3`,slots:{L:null,C:null,R:null}}},{id:`L31_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`쳇...... 식은땀은 왜 이렇게 많이 나고 난리야.`,JPN:`ちっ……冷や汗でびしょびしょじゃないか。`,ENG:`Tsk... Why did I sweat so much?`,TWN:`切……為什麼冒出這麼多冷汗。`},stage:{bg:`dormitory_3`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`여긴 씻을 물도 없는데.`,JPN:`ここは洗い流す水もないのに。`,ENG:`I can't even take a shower here.`,TWN:`這裡可沒地方洗臉啊。`},stage:{bg:`dormitory_3`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};